1	use super::*;
2	
3	/// Configuration validator
4	pub(crate) struct ConfigValidator;
5	
6	impl ConfigValidator {
7	    pub(crate) fn validate(config: &RouterConfig) -> ConfigResult<()> {
8	        Self::validate_mode(&config.mode)?;
9	        Self::validate_policy(&config.policy)?;
10	        Self::validate_server_settings(config)?;
11	
12	        if let Some(discovery) = &config.discovery {
13	            Self::validate_discovery(discovery, &config.mode)?;
14	        }
15	
16	        if let Some(metrics) = &config.metrics {
17	            Self::validate_metrics(metrics)?;
18	        }
19	
20	        if let Some(trace_config) = &config.trace_config {
21	            Self::validate_trace(trace_config)?;
22	        }
23	
24	        Self::validate_compatibility(config)?;
25	
26	        let retry_cfg = config.effective_retry_config();
27	        let cb_cfg = config.effective_circuit_breaker_config();
28	        Self::validate_retry(&retry_cfg)?;
29	        Self::validate_circuit_breaker(&cb_cfg)?;
30	
31	        if config.history_backend == HistoryBackend::Oracle {
32	            if config.oracle.is_none() {
33	                return Err(ConfigError::MissingRequired {
34	                    field: "oracle".to_string(),
35	                });
36	            }
37	            if let Some(oracle) = &config.oracle {
38	                Self::validate_oracle(oracle)?;
39	            }
40	        }
41	
42	        Self::validate_tokenizer_cache(&config.tokenizer_cache)?;
43	
44	        Ok(())
45	    }
46	
47	    fn validate_oracle(oracle: &OracleConfig) -> ConfigResult<()> {
48	        if oracle.username.is_empty() {
49	            return Err(ConfigError::MissingRequired {
50	                field: "oracle.username".to_string(),
51	            });
52	        }
53	
54	        if oracle.password.is_empty() {
55	            return Err(ConfigError::MissingRequired {
56	                field: "oracle.password".to_string(),
57	            });
58	        }
59	
60	        if oracle.connect_descriptor.is_empty() {
61	            return Err(ConfigError::MissingRequired {
62	                field: "oracle_dsn or oracle_tns_alias".to_string(),
63	            });
64	        }
65	
66	        if oracle.pool_min < 1 {
67	            return Err(ConfigError::InvalidValue {
68	                field: "oracle.pool_min".to_string(),
69	                value: oracle.pool_min.to_string(),
70	                reason: "Must be at least 1".to_string(),
71	            });
72	        }
73	
74	        if oracle.pool_max < oracle.pool_min {
75	            return Err(ConfigError::InvalidValue {
76	                field: "oracle.pool_max".to_string(),
77	                value: oracle.pool_max.to_string(),
78	                reason: "Must be >= oracle.pool_min".to_string(),
79	            });
80	        }
81	
82	        if oracle.pool_timeout_secs == 0 {
83	            return Err(ConfigError::InvalidValue {
84	                field: "oracle.pool_timeout_secs".to_string(),
85	                value: oracle.pool_timeout_secs.to_string(),
86	                reason: "Must be > 0".to_string(),
87	            });
88	        }
89	
90	        Ok(())
91	    }
92	
93	    fn validate_mode(mode: &RoutingMode) -> ConfigResult<()> {
94	        match mode {
95	            RoutingMode::Regular { worker_urls } => {
96	                if !worker_urls.is_empty() {
97	                    Self::validate_urls(worker_urls)?;
98	                }
99	                // Allow empty URLs without service discovery to match legacy behavior
100	            }
101	            RoutingMode::PrefillDecode {
102	                prefill_urls,
103	                decode_urls,
104	                prefill_policy,
105	                decode_policy,
106	            } => {
107	                // Allow empty URLs even without service discovery to support dynamic worker addition
108	                // URLs will be validated if provided
109	                if !prefill_urls.is_empty() {
110	                    let prefill_url_strings: Vec<String> =
111	                        prefill_urls.iter().map(|(url, _)| url.clone()).collect();
112	                    Self::validate_urls(&prefill_url_strings)?;
113	                }
114	                if !decode_urls.is_empty() {
115	                    Self::validate_urls(decode_urls)?;
116	                }
117	
118	                for (_url, port) in prefill_urls {
119	                    if let Some(port) = port {
120	                        if *port == 0 {
121	                            return Err(ConfigError::InvalidValue {
122	                                field: "bootstrap_port".to_string(),
123	                                value: port.to_string(),
124	                                reason: "Port must be between 1 and 65535".to_string(),
125	                            });
126	                        }
127	                    }
128	                }
129	
130	                if let Some(p_policy) = prefill_policy {
131	                    Self::validate_policy(p_policy)?;
132	                }
133	                if let Some(d_policy) = decode_policy {
134	                    Self::validate_policy(d_policy)?;
135	                }
136	            }
137	            RoutingMode::OpenAI { worker_urls } => {
138	                // Allow empty URLs to support dynamic worker addition
139	                // URLs will be validated if provided
140	                if !worker_urls.is_empty() {
141	                    Self::validate_urls(worker_urls)?;
142	                }
143	            }
144	        }
145	        Ok(())
146	    }
147	
148	    fn validate_policy(policy: &PolicyConfig) -> ConfigResult<()> {
149	        match policy {
150	            PolicyConfig::Random
151	            | PolicyConfig::RoundRobin
152	            | PolicyConfig::Manual { .. }
153	            | PolicyConfig::ConsistentHashing => {}
154	            PolicyConfig::CacheAware {
155	                cache_threshold,
156	                balance_abs_threshold: _,
157	                balance_rel_threshold,
158	                eviction_interval_secs,
159	                max_tree_size,
160	            } => {
161	                if !(0.0..=1.0).contains(cache_threshold) {
162	                    return Err(ConfigError::InvalidValue {
163	                        field: "cache_threshold".to_string(),
164	                        value: cache_threshold.to_string(),
165	                        reason: "Must be between 0.0 and 1.0".to_string(),
166	                    });
167	                }
168	
169	                if *balance_rel_threshold < 1.0 {
170	                    return Err(ConfigError::InvalidValue {
171	                        field: "balance_rel_threshold".to_string(),
172	                        value: balance_rel_threshold.to_string(),
173	                        reason: "Must be >= 1.0".to_string(),
174	                    });
175	                }
176	
177	                if *eviction_interval_secs == 0 {
178	                    return Err(ConfigError::InvalidValue {
179	                        field: "eviction_interval_secs".to_string(),
180	                        value: eviction_interval_secs.to_string(),
181	                        reason: "Must be > 0".to_string(),
182	                    });
183	                }
184	
185	                if *max_tree_size == 0 {
186	                    return Err(ConfigError::InvalidValue {
187	                        field: "max_tree_size".to_string(),
188	                        value: max_tree_size.to_string(),
189	                        reason: "Must be > 0".to_string(),
190	                    });
191	                }
192	            }
193	            PolicyConfig::PowerOfTwo {
194	                load_check_interval_secs,
195	            } => {
196	                if *load_check_interval_secs == 0 {
197	                    return Err(ConfigError::InvalidValue {
198	                        field: "load_check_interval_secs".to_string(),
199	                        value: load_check_interval_secs.to_string(),
200	                        reason: "Must be > 0".to_string(),
201	                    });
202	                }
203	            }
204	            PolicyConfig::Bucket {
205	                balance_abs_threshold: _,
206	                balance_rel_threshold,
207	                bucket_adjust_interval_secs,
208	            } => {
209	                if *balance_rel_threshold < 1.0 {
210	                    return Err(ConfigError::InvalidValue {
211	                        field: "balance_rel_threshold".to_string(),
212	                        value: balance_rel_threshold.to_string(),
213	                        reason: "Must be >= 1.0".to_string(),
214	                    });
215	                }
216	
217	                if *bucket_adjust_interval_secs < 1 {
218	                    return Err(ConfigError::InvalidValue {
219	                        field: "bucket_adjust_interval_secs".to_string(),
220	                        value: bucket_adjust_interval_secs.to_string(),
221	                        reason: "Must be >= 1s".to_string(),
222	                    });
223	                }
224	                if *bucket_adjust_interval_secs >= 4294967296 {
225	                    return Err(ConfigError::InvalidValue {
226	                        field: "bucket_adjust_interval_secs".to_string(),
227	                        value: bucket_adjust_interval_secs.to_string(),
228	                        reason: "Must be < 4294967296s".to_string(),
229	                    });
230	                }
231	            }
232	            PolicyConfig::PrefixHash {
233	                prefix_token_count,
234	                load_factor,
235	            } => {
236	                if *prefix_token_count == 0 {
237	                    return Err(ConfigError::InvalidValue {
238	                        field: "prefix_token_count".to_string(),
239	                        value: prefix_token_count.to_string(),
240	                        reason: "Must be > 0".to_string(),
241	                    });
242	                }
243	
244	                if *load_factor < 1.0 {
245	                    return Err(ConfigError::InvalidValue {
246	                        field: "load_factor".to_string(),
247	                        value: load_factor.to_string(),
248	                        reason: "Must be >= 1.0".to_string(),
249	                    });
250	                }
251	            }
252	        }
253	        Ok(())
254	    }
255	
256	    fn validate_server_settings(config: &RouterConfig) -> ConfigResult<()> {
257	        if config.port == 0 {
258	            return Err(ConfigError::InvalidValue {
259	                field: "port".to_string(),
260	                value: config.port.to_string(),
261	                reason: "Port must be > 0".to_string(),
262	            });
263	        }
264	
265	        if config.max_payload_size == 0 {
266	            return Err(ConfigError::InvalidValue {
267	                field: "max_payload_size".to_string(),
268	                value: config.max_payload_size.to_string(),
269	                reason: "Must be > 0".to_string(),
270	            });
271	        }
272	
273	        if config.request_timeout_secs == 0 {
274	            return Err(ConfigError::InvalidValue {
275	                field: "request_timeout_secs".to_string(),
276	                value: config.request_timeout_secs.to_string(),
277	                reason: "Must be > 0".to_string(),
278	            });
279	        }
280	
281	        if config.queue_size > 0 && config.queue_timeout_secs == 0 {
282	            return Err(ConfigError::InvalidValue {
283	                field: "queue_timeout_secs".to_string(),
284	                value: config.queue_timeout_secs.to_string(),
285	                reason: "Must be > 0 when queue_size > 0".to_string(),
286	            });
287	        }
288	
289	        if let Some(tokens_per_second) = config.rate_limit_tokens_per_second {
290	            // Allow 0 for pure concurrency limiting (semaphore behavior)
291	            if tokens_per_second < 0 {
292	                return Err(ConfigError::InvalidValue {
293	                    field: "rate_limit_tokens_per_second".to_string(),
294	                    value: tokens_per_second.to_string(),
295	                    reason: "Must be >= 0 when specified".to_string(),
296	                });
297	            }
298	        }
299	
300	        if config.worker_startup_timeout_secs == 0 {
301	            return Err(ConfigError::InvalidValue {
302	                field: "worker_startup_timeout_secs".to_string(),
303	                value: config.worker_startup_timeout_secs.to_string(),
304	                reason: "Must be > 0".to_string(),
305	            });
306	        }
307	
308	        if config.worker_startup_check_interval_secs == 0 {
309	            return Err(ConfigError::InvalidValue {
310	                field: "worker_startup_check_interval_secs".to_string(),
311	                value: config.worker_startup_check_interval_secs.to_string(),
312	                reason: "Must be > 0".to_string(),
313	            });
314	        }
315	
316	        if config.connect_timeout_secs == 0 {
317	            return Err(ConfigError::InvalidValue {
318	                field: "connect_timeout_secs".to_string(),
319	                value: config.connect_timeout_secs.to_string(),
320	                reason: "Must be > 0".to_string(),
321	            });
322	        }
323	
324	        if config.tcp_keepalive_secs == 0 {
325	            return Err(ConfigError::InvalidValue {
326	                field: "tcp_keepalive_secs".to_string(),
327	                value: config.tcp_keepalive_secs.to_string(),
328	                reason: "Must be > 0".to_string(),
329	            });
330	        }
331	
332	        Ok(())
333	    }
334	
335	    fn validate_discovery(discovery: &DiscoveryConfig, mode: &RoutingMode) -> ConfigResult<()> {
336	        if !discovery.enabled {
337	            return Ok(());
338	        }
339	
340	        if discovery.port == 0 {
341	            return Err(ConfigError::InvalidValue {
342	                field: "discovery.port".to_string(),
343	                value: discovery.port.to_string(),
344	                reason: "Port must be > 0".to_string(),
345	            });
346	        }
347	
348	        if discovery.check_interval_secs == 0 {
349	            return Err(ConfigError::InvalidValue {
350	                field: "discovery.check_interval_secs".to_string(),
351	                value: discovery.check_interval_secs.to_string(),
352	                reason: "Must be > 0".to_string(),
353	            });
354	        }
355	
356	        match mode {
357	            RoutingMode::Regular { .. } => {
358	                if discovery.selector.is_empty() {
359	                    return Err(ConfigError::ValidationFailed {
360	                        reason: "Regular mode with service discovery requires a non-empty selector"
361	                            .to_string(),
362	                    });
363	                }
364	            }
365	            RoutingMode::PrefillDecode { .. } => {
366	                if discovery.prefill_selector.is_empty() && discovery.decode_selector.is_empty() {
367	                    return Err(ConfigError::ValidationFailed {
368	                        reason: "PD mode with service discovery requires at least one non-empty selector (prefill or decode)".to_string(),
369	                    });
370	                }
371	            }
372	            RoutingMode::OpenAI { .. } => {
373	                return Err(ConfigError::ValidationFailed {
374	                    reason: "OpenAI mode does not support service discovery".to_string(),
375	                });
376	            }
377	        }
378	
379	        Ok(())
380	    }
381	
382	    fn validate_metrics(metrics: &MetricsConfig) -> ConfigResult<()> {
383	        if metrics.port == 0 {
384	            return Err(ConfigError::InvalidValue {
385	                field: "metrics.port".to_string(),
386	                value: metrics.port.to_string(),
387	                reason: "Port must be > 0".to_string(),
388	            });
389	        }
390	
391	        if metrics.host.is_empty() {
392	            return Err(ConfigError::InvalidValue {
393	                field: "metrics.host".to_string(),
394	                value: metrics.host.clone(),
395	                reason: "Host cannot be empty".to_string(),
396	            });
397	        }
398	
399	        Ok(())
400	    }
401	
402	    fn validate_trace(trace_config: &TraceConfig) -> ConfigResult<()> {
403	        if !trace_config.enable_trace {
404	            return Ok(());
405	        }
406	
407	        let endpoint = &trace_config.otlp_traces_endpoint;
408	
409	        let Some((host, port_str)) = endpoint.rsplit_once(':') else {
410	            return Err(ConfigError::InvalidValue {
411	                field: "trace_config.otlp_traces_endpoint".to_string(),
412	                value: endpoint.clone(),
413	                reason:
414	                    "expected format <host>:<port>, e.g., otel-collector:4317 or 127.0.0.1:4317"
415	                        .to_string(),
416	            });
417	        };
418	
419	        if host.is_empty() {
420	            return Err(ConfigError::InvalidValue {
421	                field: "trace_config.otlp_traces_endpoint".to_string(),
422	                value: endpoint.clone(),
423	                reason: "host part cannot be empty".to_string(),
424	            });
425	        }
426	
427	        // check port: must be 1~65535
428	        match port_str.parse::<u16>() {
429	            Ok(p) if p > 0 => (), // valid port
430	            _ => {
431	                return Err(ConfigError::InvalidValue {
432	                    field: "trace_config.otlp_traces_endpoint".to_string(),
433	                    value: endpoint.clone(),
434	                    reason: "port must be a number between 1 and 65535".to_string(),
435	                });
436	            }
437	        };
438	
439	        Ok(())
440	    }
441	
442	    fn validate_retry(retry: &RetryConfig) -> ConfigResult<()> {
443	        if retry.max_retries < 1 {
444	            return Err(ConfigError::InvalidValue {
445	                field: "retry.max_retries".to_string(),
446	                value: retry.max_retries.to_string(),
447	                reason: "Must be >= 1 (set to 1 to effectively disable retries)".to_string(),
448	            });
449	        }
450	        if retry.initial_backoff_ms == 0 {
451	            return Err(ConfigError::InvalidValue {
452	                field: "retry.initial_backoff_ms".to_string(),
453	                value: retry.initial_backoff_ms.to_string(),
454	                reason: "Must be > 0".to_string(),
455	            });
456	        }
457	        if retry.max_backoff_ms < retry.initial_backoff_ms {
458	            return Err(ConfigError::InvalidValue {
459	                field: "retry.max_backoff_ms".to_string(),
460	                value: retry.max_backoff_ms.to_string(),
461	                reason: "Must be >= initial_backoff_ms".to_string(),
462	            });
463	        }
464	        if retry.backoff_multiplier < 1.0 {
465	            return Err(ConfigError::InvalidValue {
466	                field: "retry.backoff_multiplier".to_string(),
467	                value: retry.backoff_multiplier.to_string(),
468	                reason: "Must be >= 1.0".to_string(),
469	            });
470	        }
471	        if !(0.0..=1.0).contains(&retry.jitter_factor) {
472	            return Err(ConfigError::InvalidValue {
473	                field: "retry.jitter_factor".to_string(),
474	                value: retry.jitter_factor.to_string(),
475	                reason: "Must be between 0.0 and 1.0".to_string(),
476	            });
477	        }
478	        Ok(())
479	    }
480	
481	    fn validate_circuit_breaker(cb: &CircuitBreakerConfig) -> ConfigResult<()> {
482	        if cb.failure_threshold < 1 {
483	            return Err(ConfigError::InvalidValue {
484	                field: "circuit_breaker.failure_threshold".to_string(),
485	                value: cb.failure_threshold.to_string(),
486	                reason: "Must be >= 1 (set to u32::MAX to effectively disable CB)".to_string(),
487	            });
488	        }
489	        if cb.success_threshold < 1 {
490	            return Err(ConfigError::InvalidValue {
491	                field: "circuit_breaker.success_threshold".to_string(),
492	                value: cb.success_threshold.to_string(),
493	                reason: "Must be >= 1".to_string(),
494	            });
495	        }
496	        if cb.timeout_duration_secs == 0 {
497	            return Err(ConfigError::InvalidValue {
498	                field: "circuit_breaker.timeout_duration_secs".to_string(),
499	                value: cb.timeout_duration_secs.to_string(),
500	                reason: "Must be > 0".to_string(),
501	            });
502	        }
503	        if cb.window_duration_secs == 0 {
504	            return Err(ConfigError::InvalidValue {
505	                field: "circuit_breaker.window_duration_secs".to_string(),
506	                value: cb.window_duration_secs.to_string(),
507	                reason: "Must be > 0".to_string(),
508	            });
509	        }
510	        Ok(())
511	    }
512	
513	    fn validate_tokenizer_cache(cache: &TokenizerCacheConfig) -> ConfigResult<()> {
514	        if cache.enable_l0 && cache.l0_max_entries == 0 {
515	            return Err(ConfigError::InvalidValue {
516	                field: "tokenizer_cache.l0_max_entries".to_string(),
517	                value: cache.l0_max_entries.to_string(),
518	                reason: "Must be > 0 when L0 cache is enabled".to_string(),
519	            });
520	        }
521	
522	        if cache.enable_l1 && cache.l1_max_memory == 0 {
523	            return Err(ConfigError::InvalidValue {
524	                field: "tokenizer_cache.l1_max_memory".to_string(),
525	                value: cache.l1_max_memory.to_string(),
526	                reason: "Must be > 0 when L1 cache is enabled".to_string(),
527	            });
528	        }
529	
530	        Ok(())
531	    }
532	
533	    fn validate_mtls(config: &RouterConfig) -> ConfigResult<()> {
534	        if let Some(identity) = &config.client_identity {
535	            if identity.is_empty() {
536	                return Err(ConfigError::ValidationFailed {
537	                    reason: "Client identity cannot be empty".to_string(),
538	                });
539	            }
540	        }
541	
542	        for (idx, ca_cert) in config.ca_certificates.iter().enumerate() {
543	            if ca_cert.is_empty() {
544	                return Err(ConfigError::ValidationFailed {
545	                    reason: format!("CA certificate at index {} cannot be empty", idx),
546	                });
547	            }
548	        }
549	
550	        Ok(())
551	    }
552	
553	    fn validate_compatibility(config: &RouterConfig) -> ConfigResult<()> {
554	        if config.enable_igw {
555	            return Ok(());
556	        }
557	
558	        Self::validate_mtls(config)?;
559	
560	        let has_service_discovery = config.discovery.as_ref().is_some_and(|d| d.enabled);
561	
562	        if !has_service_discovery {
563	            if let PolicyConfig::PowerOfTwo { .. } = &config.policy {
564	                let worker_count = config.mode.worker_count();
565	                if worker_count < 2 {
566	                    return Err(ConfigError::IncompatibleConfig {
567	                        reason: "Power-of-two policy requires at least 2 workers".to_string(),
568	                    });
569	                }
570	            }
571	
572	            if let RoutingMode::PrefillDecode {
573	                prefill_urls,
574	                decode_urls,
575	                prefill_policy,
576	                decode_policy,
577	            } = &config.mode
578	            {
579	                if let Some(PolicyConfig::PowerOfTwo { .. }) = prefill_policy {
580	                    if prefill_urls.len() < 2 {
581	                        return Err(ConfigError::IncompatibleConfig {
582	                            reason: "Power-of-two policy for prefill requires at least 2 prefill workers".to_string(),
583	                        });
584	                    }
585	                }
586	
587	                if let Some(PolicyConfig::PowerOfTwo { .. }) = decode_policy {
588	                    if decode_urls.len() < 2 {
589	                        return Err(ConfigError::IncompatibleConfig {
590	                            reason:
591	                                "Power-of-two policy for decode requires at least 2 decode workers"
592	                                    .to_string(),
593	                        });
594	                    }
595	                }
596	
597	                // Check bucket for decode
598	                if let Some(PolicyConfig::Bucket { .. }) = decode_policy {
599	                    return Err(ConfigError::IncompatibleConfig {
600	                        reason: "Decode policy should not be allowed to be bucket".to_string(),
601	                    });
602	                }
603	            }
604	        }
605	
606	        Ok(())
607	    }
608	
609	    fn validate_urls(urls: &[String]) -> ConfigResult<()> {
610	        for url in urls {
611	            if url.is_empty() {
612	                return Err(ConfigError::InvalidValue {
613	                    field: "worker_url".to_string(),
614	                    value: url.clone(),
615	                    reason: "URL cannot be empty".to_string(),
616	                });
617	            }
618	
619	            if !url.starts_with("http://")
620	                && !url.starts_with("https://")
621	                && !url.starts_with("grpc://")
622	            {
623	                return Err(ConfigError::InvalidValue {
624	                    field: "worker_url".to_string(),
625	                    value: url.clone(),
626	                    reason: "URL must start with http://, https://, or grpc://".to_string(),
627	                });
628	            }
629	
630	            match ::url::Url::parse(url) {
631	                Ok(parsed) => {
632	                    if parsed.host_str().is_none() {
633	                        return Err(ConfigError::InvalidValue {
634	                            field: "worker_url".to_string(),
635	                            value: url.clone(),
636	                            reason: "URL must have a valid host".to_string(),
637	                        });
638	                    }
639	                }
640	                Err(e) => {
641	                    return Err(ConfigError::InvalidValue {
642	                        field: "worker_url".to_string(),
643	                        value: url.clone(),
644	                        reason: format!("Invalid URL format: {}", e),
645	                    });
646	                }
647	            }
648	        }
649	        Ok(())
650	    }
651	}
