663	    // ==================== Build ====================
664	
665	    pub fn build(self) -> ConfigResult<RouterConfig> {
666	        self.build_with_validation(true)
667	    }
668	
669	    pub fn build_unchecked(self) -> RouterConfig {
670	        self.into()
671	    }
672	
673	    pub fn build_with_validation(mut self, validate: bool) -> ConfigResult<RouterConfig> {
674	        // Read mTLS certificates from paths if provided
675	        self = self.read_mtls_certificates()?;
676	
677	        // Read Server TLS certificates from paths if provided
678	        self = self.read_server_certificates()?;
679	
680	        // Read MCP config from path if provided
681	        self = self.read_mcp_config()?;
682	
683	        let config: RouterConfig = self.into();
684	        if validate {
685	            config.validate()?;
686	        }
687	        Ok(config)
688	    }
689	
690	    /// Internal method to read mTLS certificates from paths
691	    fn read_mtls_certificates(mut self) -> ConfigResult<Self> {
692	        // Read client certificate and key
693	        match (&self.client_cert_path, &self.client_key_path) {
694	            (Some(cert_path), Some(key_path)) => {
695	                let cert = std::fs::read(cert_path).map_err(|e| ConfigError::ValidationFailed {
696	                    reason: format!(
697	                        "Failed to read client certificate from {}: {}",
698	                        cert_path, e
699	                    ),
700	                })?;
701	                let key = std::fs::read(key_path).map_err(|e| ConfigError::ValidationFailed {
702	                    reason: format!("Failed to read client key from {}: {}", key_path, e),
703	                })?;
704	
705	                // Combine cert and key into single PEM for reqwest::Identity
706	                // When using rustls, certificate must come first, then key
707	                // Ensure proper PEM formatting with newlines
708	                let mut combined = cert;
709	                if !combined.ends_with(b"\n") {
710	                    combined.push(b'\n');
711	                }
712	                combined.extend_from_slice(&key);
713	                if !combined.ends_with(b"\n") {
714	                    combined.push(b'\n');
715	                }
716	
717	                self.config.client_identity = Some(combined);
718	            }
719	            (None, None) => {
720	                // No client cert configured, that's fine
721	            }
722	            _ => {
723	                return Err(ConfigError::ValidationFailed {
724	                    reason:
725	                        "Both --client-cert-path and --client-key-path must be specified together"
726	                            .to_string(),
727	                });
728	            }
729	        }
730	
731	        // Read CA certificates
732	        for path in &self.ca_cert_paths {
733	            let cert = std::fs::read(path).map_err(|e| ConfigError::ValidationFailed {
734	                reason: format!("Failed to read CA certificate from {}: {}", path, e),
735	            })?;
736	            self.config.ca_certificates.push(cert);
737	        }
738	
739	        Ok(self)
740	    }
741	
742	    /// Internal method to read Server TLS certificates from paths
743	    fn read_server_certificates(mut self) -> ConfigResult<Self> {
744	        match (&self.server_cert_path, &self.server_key_path) {
745	            (Some(cert_path), Some(key_path)) => {
746	                let cert = std::fs::read(cert_path).map_err(|e| ConfigError::ValidationFailed {
747	                    reason: format!(
748	                        "Failed to read server certificate from {}: {}",
749	                        cert_path, e
750	                    ),
751	                })?;
752	                let key = std::fs::read(key_path).map_err(|e| ConfigError::ValidationFailed {
753	                    reason: format!("Failed to read server key from {}: {}", key_path, e),
754	                })?;
755	                self.config.server_cert = Some(cert);
756	                self.config.server_key = Some(key);
757	            }
758	            (None, None) => {}
759	            _ => {
760	                return Err(ConfigError::ValidationFailed {
761	                    reason: "Both --tls-cert-path and --tls-key-path must be specified together"
762	                        .to_string(),
763	                });
764	            }
765	        }
766	        Ok(self)
767	    }
768	
769	    /// Internal method to read MCP config from path
770	    fn read_mcp_config(mut self) -> ConfigResult<Self> {
771	        if let Some(mcp_config_path) = &self.mcp_config_path {
772	            let contents = std::fs::read_to_string(mcp_config_path).map_err(|e| {
773	                ConfigError::ValidationFailed {
774	                    reason: format!("Failed to read MCP config from {}: {}", mcp_config_path, e),
775	                }
776	            })?;
777	            let mcp_config: McpConfig =
778	                serde_yaml::from_str(&contents).map_err(|e| ConfigError::ValidationFailed {
779	                    reason: format!("Failed to parse MCP config from {}: {}", mcp_config_path, e),
780	                })?;
781	            self.config.mcp_config = Some(mcp_config);
782	        }
783	
784	        Ok(self)
785	    }
786	}
787	
788	impl From<RouterConfigBuilder> for RouterConfig {
789	    fn from(builder: RouterConfigBuilder) -> Self {
790	        builder.config
791	    }
792	}
